import React, { useState, useRef, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './Header.css';
import SearchBar from './SearchBar';
import UserMenu from './UserMenu';
import CatalogDropdown from '../Dropdown/CatalogDropdown';


const Header = () => {
  const [isCatalogOpen, setIsCatalogOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const catalogRef = useRef(null);

  // Mobile menyuni ochish/yopish
  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  // Mobile menyu ochiq bo'lsa, catalog dropdown yopiladi
  useEffect(() => {
    if (isMobileMenuOpen) {
      setIsCatalogOpen(false);
    }
  }, [isMobileMenuOpen]);

  // Catalog dropdown uchun mouse eventlar
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (catalogRef.current && !catalogRef.current.contains(event.target)) {
        setIsCatalogOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  return (
    <header className="header">
      <div className="header-container">
        {/* Logo */}
        <div className="logo-section">
          <Link to="/" className="logo" onClick={() => setIsMobileMenuOpen(false)}>
            <img src="/logo.png" alt="MangaUz" />
            <span className="logo-text">MangaUz</span>
          </Link>
        </div>

        {/* Navigation */}
        <nav className={`nav-section ${isMobileMenuOpen ? 'active' : ''}`}>
          {/* Catalog Dropdown */}
          <div 
            className="catalog-link"
            ref={catalogRef}
          >
            <button 
              className="catalog-btn"
              onClick={() => {
                setIsCatalogOpen(!isCatalogOpen);
                if (window.innerWidth <= 768) {
                  setIsMobileMenuOpen(false);
                }
              }}
            >
              <i className="fas fa-bars"></i>
              Каталог
            </button>
            {isCatalogOpen && (
              <div className="catalog-dropdown-wrapper">
                <CatalogDropdown />
              </div>
            )}
          </div>

          {/* Forum Link */}
          <Link to="/forum" className="nav-link" onClick={() => setIsMobileMenuOpen(false)}>
            <i className="fas fa-comments"></i>
            Форум
          </Link>

          {/* Search Bar */}
          <div className="search-container">
            <SearchBar />
          </div>
        </nav>

        {/* User Menu */}
        <div className="user-section">
          <UserMenu />
        </div>

        {/* Mobile Menu Button */}
        <button 
          className="mobile-menu-btn" 
          onClick={toggleMobileMenu}
          aria-label="Toggle menu"
        >
          <i className={`fas ${isMobileMenuOpen ? 'fa-times' : 'fa-bars'}`}></i>
        </button>
      </div>
    </header>
  );
};

export default Header;
